sql:
SELECT name 
FROM freelancers 
WHERE rating_average = (SELECT MAX(rating_average) FROM freelancers);

SELECT name
FROM freelancers
WHERE category_id = (SELECT category_id FROM categories WHERE category_name = 'Graphics & Design');

SELECT COUNT(DISTINCT p.client_id) AS completed_clients_count
FROM projects p
WHERE p.status = 'completed';

SELECT name
FROM freelancers
WHERE rating_average > 4.5;

SELECT 
  (SELECT COUNT(*) FROM projects) AS total_projects,
  (SELECT SUM(amount) FROM transactions) AS total_amount_spent;

SELECT 
  (SELECT COUNT(DISTINCT freelancer_id) FROM freelancers) AS number_of_freelancers,
  (SELECT SUM(budget) FROM projects) AS total_project_budget;
